	// Group points by y-coordinate
	yGroups := make(map[int64][]int64)
	for _, p := range points {
		yGroups[p[1]] = append(yGroups[p[1]], p[0])
	}

	result := int64(0)

	// Sort the y-coordinates to process in order
	yKeys := make([]int64, 0, len(yGroups))
	for y := range yGroups {
		yKeys = append(yKeys, y)
	}
	sort.Int64s(yKeys)

	// Process each pair of y-levels
	for i := 0; i < len(yKeys); i++ {
		y1 := yKeys[i]
		xs1 := yGroups[y1]
		sort.Int64s(xs1)
		n1 := len(xs1)

		for j := i + 1; j < len(yKeys); j++ {
			y2 := yKeys[j]
			xs2 := yGroups[y2]
			sort.Int64s(xs2)
			n2 := len(xs2)

			// Calculate combinations C(n, 2)
			c1 := int64(n1) * int64(n1-1) / 2
			c2 := int64(n2) * int64(n2-1) / 2

			result = (result + c1*c2) % MOD
		}
	}

	return result
}
